import React, { useState, useEffect, useRef } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const ReelsFeed = () => {
  const { user } = useAuth();
  const [reels, setReels] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [liked, setLiked] = useState({});
  const videoRefs = useRef([]);
  const containerRef = useRef(null);

  useEffect(() => {
    fetchReels();
  }, []);

  useEffect(() => {
    // Auto-play current video when scrolled into view
    if (videoRefs.current[currentIndex]) {
      videoRefs.current[currentIndex].play().catch(() => {});
    }
  }, [currentIndex]);

  const fetchReels = async () => {
    try {
      const res = await api.get('/reels');
      setReels(res.data || []);
    } catch (error) {
      console.error('Error fetching reels:', error);
      setReels([]);
    } finally {
      setLoading(false);
    }
  };

  const handleScroll = (e) => {
    const scrollTop = e.target.scrollTop;
    const height = e.target.clientHeight;
    const newIndex = Math.round(scrollTop / height);

    if (newIndex !== currentIndex && newIndex < reels.length && newIndex >= 0) {
      // Pause previous video
      if (videoRefs.current[currentIndex]) {
        videoRefs.current[currentIndex].pause();
      }
      setCurrentIndex(newIndex);
    }
  };

  const handleLike = async (reelId) => {
    try {
      await api.post(`/reels/${reelId}/like`);
      setLiked((prev) => ({ ...prev, [reelId]: !prev[reelId] }));
      // Update view count
      setReels(reels.map(reel =>
        reel._id === reelId ? { ...reel, likes: reel.likes + 1 } : reel
      ));
    } catch (error) {
      console.error('Error liking reel:', error);
    }
  };

  const handleShare = (reel) => {
    const text = `Check out this movie edit: "${reel.title}"`;
    if (navigator.share) {
      navigator.share({
        title: 'Movie Edit',
        text,
        url: window.location.origin
      }).catch(() => {});
    } else {
      // Fallback: copy to clipboard
      navigator.clipboard.writeText(`${reel.title} - Check out this awesome movie edit on Cineverse!`);
      alert('Share link copied to clipboard!');
    }
  };

  if (loading) {
    return (
      <div className="h-screen flex items-center justify-center bg-black text-white">
        <div className="flex flex-col items-center gap-4">
          <div className="w-10 h-10 border-2 border-purple-500 border-t-transparent rounded-full animate-spin" />
          <p className="text-gray-400 text-sm">Loading movie edits...</p>
        </div>
      </div>
    );
  }

  if (reels.length === 0) {
    return (
      <div className="h-screen flex items-center justify-center bg-black text-white">
        <div className="text-center">
          <div className="text-4xl mb-4">🎬</div>
          <p className="text-gray-400 mb-4">No movie edits yet</p>
          {user && (
            <p className="text-sm text-gray-500">Be the first to upload a movie edit!</p>
          )}
        </div>
      </div>
    );
  }

  const currentReel = reels[currentIndex];

  return (
    <div
      ref={containerRef}
      className="h-screen overflow-y-scroll snap-y snap-mandatory bg-black"
      onScroll={handleScroll}
    >
      {reels.map((reel, index) => (
        <div
          key={reel._id}
          className="h-screen snap-start relative flex items-center justify-center bg-black"
        >
          {/* Video */}
          <video
            ref={(el) => (videoRefs.current[index] = el)}
            className="h-full w-full object-contain"
            src={`http://localhost:5000${reel.videoUrl}`}
            loop
            playsInline
            muted={index !== currentIndex}
          />

          {/* Right side actions */}
          <div className="absolute right-4 bottom-32 flex flex-col items-center gap-5 z-20">
            {/* Like */}
            <button
              onClick={() => handleLike(reel._id)}
              className="flex flex-col items-center hover:scale-110 transition"
            >
              <span className={`text-3xl ${liked[reel._id] ? 'text-red-500' : 'text-white'}`}>
                {liked[reel._id] ? '❤️' : '🤍'}
              </span>
              <span className="text-xs text-gray-300 mt-1">{reel.likes}</span>
            </button>

            {/* Share */}
            <button
              onClick={() => handleShare(reel)}
              className="flex flex-col items-center hover:scale-110 transition"
            >
              <span className="text-3xl">🔗</span>
              <span className="text-xs text-gray-300 mt-1">Share</span>
            </button>

            {/* Comment */}
            <button className="flex flex-col items-center hover:scale-110 transition">
              <span className="text-3xl">💬</span>
              <span className="text-xs text-gray-300 mt-1">{Math.floor(Math.random() * 100)}</span>
            </button>

            {/* More */}
            <button className="flex flex-col items-center hover:scale-110 transition">
              <span className="text-3xl">⋯</span>
              <span className="text-xs text-gray-300 mt-1">More</span>
            </button>
          </div>

          {/* Bottom info overlay */}
          <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black/95 via-black/60 to-transparent z-10">
            <div className="max-w-sm">
              <h3 className="text-xl font-bold text-white mb-2">{reel.title}</h3>
              {reel.uploadedBy && (
                <p className="text-sm text-gray-300 mb-2">
                  👤 {reel.uploadedBy.name || 'Anonymous Creator'}
                </p>
              )}
              <div className="flex items-center gap-3 text-sm text-gray-400">
                <span>👁️ {reel.views} views</span>
                <span>•</span>
                <span>🕐 {new Date(reel.createdAt).toLocaleDateString()}</span>
              </div>
            </div>
          </div>

          {/* Progress indicator */}
          <div className="absolute top-4 right-4 bg-black/60 px-3 py-1 rounded-full text-xs text-gray-300 z-20">
            {index + 1} / {reels.length}
          </div>
        </div>
      ))}
    </div>
  );
};

export default ReelsFeed;
